Hi, sorry to raise this issue but I just can not figure out what caused this problem. I wrote a simple face detection app in C++, and here is the mainly codes:
```
 dlib::frontal_face_detector detector = dlib::get_frontal_face_detector();

    dlib::shape_predictor sp;
    dlib::deserialize("/media/jintian/Netac/CodeSpace/ng/ai/lab/vision/face_off"
                              "/data/dlib/shape_predictor_68_face_landmarks.dat") >> sp;

    dlib::image_window win, win_faces;
    string imgPath = argv[1];
    // get image and detect it
    dlib::array2d<dlib::rgb_pixel> image;
    dlib::load_image(image, imgPath);
    dlib::pyramid_up(imgPath);

    long long detectTime = cv::getTickCount();
    vector<dlib::rectangle> detections = detector(image, 1);
    detectTime = cv::getTickCount() - detectTime;
    cout << "detect time : " << 1000 * detectTime / cv::getTickFrequency() << " ms" << endl;
    cout << "Number of faces detected: " << detections.size() << endl;

    std::vector<dlib::full_object_detection> shapes;


    //int64 t;
    long long total = cv::getTickCount();
    for (unsigned long j = 0; j < detections.size(); ++j)
    {
        long long t = cv::getTickCount();
        dlib::full_object_detection shape = sp(image, detections[j]);
        cout << "number of parts: " << shape.num_parts() << endl;
        cout << "pixel position of first part:  " << shape.part(0) << endl;
        cout << "pixel position of second part: " << shape.part(1) << endl;
        // You get the idea, you can get all the face part locations if
        // you want them.  Here we just store them in shapes so we can
        // put them on the screen.
        shapes.push_back(shape);

        t = cv::getTickCount() - t;
        cout << "process time : " << 1000 * t / cv::getTickFrequency() << " ms" << endl;
    }
    total = cv::getTickCount() - total;
    cout << "process time : " << 1000 * total / cv::getTickFrequency() << " ms" << endl;

    // Now let's view our face poses on the screen.
    win.clear_overlay();
    win.set_image(image);
    win.add_overlay(render_face_detections(shapes));

    // We can also extract copies of each face that are cropped, rotated upright,
    // and scaled to a standard size as shown here:
    dlib::array<dlib::array2d<dlib::rgb_pixel> > face_chips;
    extract_image_chips(image, get_face_chip_details(shapes), face_chips);
    win_faces.set_image(tile_images(face_chips));
```
